// 초기화 파라미터 설정
var initializeParameter = new CDeviceFfuBlueCordMcul32TotalDefine.CInitializeParameter()
{
    eType = CDeviceFfuBlueCordMcul32TotalDefine.CInitializeParameter.enumType.TYPE_SERIAL,
    strSerialPortName = "COM1",
    iSerialPortBaudrate = 19200,
    iSerialPortDataBits = 8,
    eStopBits = CDeviceFfuBlueCordMcul32TotalDefine.CInitializeParameter.enumSerialPortStopBits.STOP_BITS_ONE,
    eParity = CDeviceFfuBlueCordMcul32TotalDefine.CInitializeParameter.enumSerialPortParity.PARITY_NONE
};

// 라이브러리 초기화
var device = new CDeviceFfuBlueCordMcul32Total();
if (device.HLInitialize(initializeParameter) == false)
{
    // 초기화 실패
    return;
}

// 라이브러리 정리
device.HLDeInitialize();
return;

